## 🗄️ DATABASE SCHEMA (MySQL)

```sql
-- Users Table
CREATE TABLE users (
  id INT PRIMARY KEY AUTO_INCREMENT,
  username VARCHAR(50) UNIQUE NOT NULL,
  email VARCHAR(100) UNIQUE NOT NULL,
  phone VARCHAR(15) UNIQUE,
  password_hash VARCHAR(255) NOT NULL,
  ign VARCHAR(50),
  game_uid VARCHAR(50),
  avatar_url VARCHAR(255),
  wallet_balance DECIMAL(10, 2) DEFAULT 0,
  total_wins INT DEFAULT 0,
  total_tournaments INT DEFAULT 0,
  total_kills INT DEFAULT 0,
  referral_code VARCHAR(20) UNIQUE,
  referred_by INT,
  created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP,
  updated_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,
  is_active BOOLEAN DEFAULT TRUE,
  FOREIGN KEY (referred_by) REFERENCES users(id)
);

-- Tournaments Table
CREATE TABLE tournaments (
  id INT PRIMARY KEY AUTO_INCREMENT,
  name VARCHAR(100) NOT NULL,
  game_type ENUM('free_fire', 'bgmi', 'cod', 'valorant') DEFAULT 'free_fire',
  tournament_type ENUM('solo', 'duo', 'squad') NOT NULL,
  entry_type ENUM('free', 'paid') NOT NULL,
  entry_fee DECIMAL(10, 2) DEFAULT 0,
  max_slots INT NOT NULL,
  booked_slots INT DEFAULT 0,
  start_date DATETIME NOT NULL,
  end_date DATETIME NOT NULL,
  description TEXT,
  prize_pool DECIMAL(12, 2) DEFAULT 0,
  status ENUM('upcoming', 'live', 'completed', 'cancelled') DEFAULT 'upcoming',
  created_by INT NOT NULL,
  created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP,
  updated_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,
  FOREIGN KEY (created_by) REFERENCES users(id)
);

-- Tournament Registrations Table
CREATE TABLE tournament_registrations (
  id INT PRIMARY KEY AUTO_INCREMENT,
  tournament_id INT NOT NULL,
  user_id INT NOT NULL,
  team_name VARCHAR(100),
  team_members JSON,
  payment_status ENUM('pending', 'completed', 'failed', 'refunded') DEFAULT 'pending',
  amount_paid DECIMAL(10, 2) DEFAULT 0,
  registration_date TIMESTAMP DEFAULT CURRENT_TIMESTAMP,
  UNIQUE KEY unique_registration (tournament_id, user_id),
  FOREIGN KEY (tournament_id) REFERENCES tournaments(id) ON DELETE CASCADE,
  FOREIGN KEY (user_id) REFERENCES users(id) ON DELETE CASCADE
);

-- Matches Table
CREATE TABLE matches (
  id INT PRIMARY KEY AUTO_INCREMENT,
  tournament_id INT NOT NULL,
  match_number INT,
  room_id VARCHAR(50),
  room_password VARCHAR(50),
  scheduled_time DATETIME NOT NULL,
  status ENUM('scheduled', 'live', 'completed', 'cancelled') DEFAULT 'scheduled',
  map_name VARCHAR(50),
  notes TEXT,
  created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP,
  updated_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,
  FOREIGN KEY (tournament_id) REFERENCES tournaments(id) ON DELETE CASCADE
);

-- Match Results Table
CREATE TABLE match_results (
  id INT PRIMARY KEY AUTO_INCREMENT,
  match_id INT NOT NULL,
  user_id INT NOT NULL,
  kills INT DEFAULT 0,
  placement INT,
  points INT DEFAULT 0,
  team_placement INT,
  verification_status ENUM('pending', 'approved', 'rejected') DEFAULT 'pending',
  verified_by INT,
  submitted_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP,
  verified_at TIMESTAMP NULL,
  UNIQUE KEY unique_result (match_id, user_id),
  FOREIGN KEY (match_id) REFERENCES matches(id) ON DELETE CASCADE,
  FOREIGN KEY (user_id) REFERENCES users(id) ON DELETE CASCADE,
  FOREIGN KEY (verified_by) REFERENCES users(id)
);

-- Transactions Table
CREATE TABLE transactions (
  id INT PRIMARY KEY AUTO_INCREMENT,
  user_id INT NOT NULL,
  transaction_type ENUM('deposit', 'withdrawal', 'entry_fee', 'winning', 'refund', 'referral_bonus') NOT NULL,
  amount DECIMAL(10, 2) NOT NULL,
  payment_method VARCHAR(50),
  transaction_id VARCHAR(100) UNIQUE,
  status ENUM('pending', 'success', 'failed', 'cancelled') DEFAULT 'pending',
  description TEXT,
  reference_id INT,
  created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP,
  updated_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,
  FOREIGN KEY (user_id) REFERENCES users(id) ON DELETE CASCADE
);

-- Leaderboard Table
CREATE TABLE leaderboards (
  id INT PRIMARY KEY AUTO_INCREMENT,
  tournament_id INT NOT NULL,
  user_id INT NOT NULL,
  total_kills INT DEFAULT 0,
  total_points INT DEFAULT 0,
  best_placement INT,
  matches_played INT DEFAULT 0,
  rank INT,
  updated_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,
  UNIQUE KEY unique_leaderboard (tournament_id, user_id),
  FOREIGN KEY (tournament_id) REFERENCES tournaments(id) ON DELETE CASCADE,
  FOREIGN KEY (user_id) REFERENCES users(id) ON DELETE CASCADE
);

-- Withdrawals Table
CREATE TABLE withdrawals (
  id INT PRIMARY KEY AUTO_INCREMENT,
  user_id INT NOT NULL,
  amount DECIMAL(10, 2) NOT NULL,
  payment_method ENUM('bank', 'upi', 'paytm') NOT NULL,
  bank_account VARCHAR(20),
  upi_id VARCHAR(100),
  paytm_number VARCHAR(15),
  status ENUM('pending', 'approved', 'rejected', 'completed') DEFAULT 'pending',
  reason_for_rejection TEXT,
  requested_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP,
  processed_at TIMESTAMP NULL,
  FOREIGN KEY (user_id) REFERENCES users(id) ON DELETE CASCADE
);

-- Support Tickets Table
CREATE TABLE support_tickets (
  id INT PRIMARY KEY AUTO_INCREMENT,
  user_id INT NOT NULL,
  category VARCHAR(50),
  subject VARCHAR(255) NOT NULL,
  message TEXT NOT NULL,
  status ENUM('open', 'in_progress', 'resolved', 'closed') DEFAULT 'open',
  priority ENUM('low', 'medium', 'high') DEFAULT 'medium',
  assigned_to INT,
  created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP,
  updated_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,
  FOREIGN KEY (user_id) REFERENCES users(id) ON DELETE CASCADE,
  FOREIGN KEY (assigned_to) REFERENCES users(id)
);

-- Create indexes for better performance
CREATE INDEX idx_user_email ON users(email);
CREATE INDEX idx_tournament_status ON tournaments(status);
CREATE INDEX idx_registration_tournament ON tournament_registrations(tournament_id);
CREATE INDEX idx_registration_user ON tournament_registrations(user_id);
CREATE INDEX idx_match_tournament ON matches(tournament_id);
CREATE INDEX idx_result_match ON match_results(match_id);
CREATE INDEX idx_transaction_user ON transactions(user_id);
CREATE INDEX idx_withdrawal_user ON withdrawals(user_id);
