```javascript
const express = require('express');
const bcrypt = require('bcryptjs');
const jwt = require('jsonwebtoken');
const { body, validationResult } = require('express-validator');
const pool = require('../config/database');
const router = express.Router();

// Register
router.post(
  '/register',
  [
    body('email').isEmail(),
    body('password').isLength({ min: 6 }),
    body('username').isLength({ min: 3 })
  ],
  async (req, res) => {
    const errors = validationResult(req);
    if (!errors.isEmpty()) {
      return res.status(400).json({ errors: errors.array() });
    }

    const { email, password, username, phone, ign, game_uid } = req.body;

    try {
      const connection = await pool.getConnection();

      // Check if user exists
      const [existingUser] = await connection.query(
        'SELECT * FROM users WHERE email = ? OR username = ?',
        [email, username]
      );

      if (existingUser.length > 0) {
        await connection.release();
        return res.status(400).json({ error: 'User already exists' });
      }

      // Hash password
      const hashedPassword = await bcrypt.hash(password, 10);
      const referralCode = Math.random().toString(36).substring(2, 10).toUpperCase();

      // Insert user
      await connection.query(
        'INSERT INTO users (email, username, password_hash, phone, ign, game_uid, referral_code) VALUES (?, ?, ?, ?, ?, ?, ?)',
        [email, username, hashedPassword, phone || null, ign || null, game_uid || null, referralCode]
      );

      await connection.release();

      res.status(201).json({ 
        message: 'User registered successfully',
        referral_code: referralCode
      });
    } catch (error) {
      console.error(error);
      res.status(500).json({ error: 'Registration failed' });
    }
  }
);

// Login
router.post('/login', async (req, res) => {
  const { email, password } = req.body;

  try {
    const connection = await pool.getConnection();

    const [users] = await connection.query(
      'SELECT * FROM users WHERE email = ?',
      [email]
    );

    if (users.length === 0) {
      await connection.release();
      return res.status(401).json({ error: 'Invalid credentials' });
    }

    const user = users[0];
    const isPasswordValid = await bcrypt.compare(password, user.password_hash);

    if (!isPasswordValid) {
      await connection.release();
      return res.status(401).json({ error: 'Invalid credentials' });
    }

    const token = jwt.sign(
      { id: user.id, role: 'user' },
      process.env.JWT_SECRET || 'secret_key',
      { expiresIn: '30d' }
    );

    await connection.release();

    res.json({
      message: 'Login successful',
      token,
      user: {
        id: user.id,
        email: user.email,
        username: user.username,
        ign: user.ign,
        wallet_balance: user.wallet_balance
      }
    });
  } catch (error) {
    console.error(error);
    res.status(500).json({ error: 'Login failed' });
  }
});

module.exports = router;
```

### **6. routes/tournaments.js**

```javascript
const express = require('express');
const pool = require('../config/database');
const { verifyToken, verifyAdmin } = require('../middleware/auth');
const router = express.Router();

// Get all tournaments
router.get('/', async (req, res) => {
  try {
    const connection = await pool.getConnection();
    const [tournaments] = await connection.query(
      'SELECT * FROM tournaments WHERE status IN ("upcoming", "live") ORDER BY start_date ASC'
    );
    await connection.release();

    res.json(tournaments);
  } catch (error) {
    res.status(500).json({ error: error.message });
  }
});

// Get tournament details
router.get('/:id', async (req, res) => {
  try {
    const connection = await pool.getConnection();
    const [tournaments] = await connection.query(
      'SELECT * FROM tournaments WHERE id = ?',
      [req.params.id]
    );

    if (tournaments.length === 0) {
      await connection.release();
      return res.status(404).json({ error: 'Tournament not found' });
    }

    const tournament = tournaments[0];

    // Get registered users count
    const [registrations] = await connection.query(
      'SELECT COUNT(*) as count FROM tournament_registrations WHERE tournament_id = ? AND payment_status = "completed"',
      [req.params.id]
    );

    await connection.release();

    res.json({
      ...tournament,
      registered_users: registrations[0].count
    });
  } catch (error) {
    res.status(500).json({ error: error.message });
  }
});

// Create tournament (Admin only)
router.post('/', verifyAdmin, async (req, res) => {
  const {
    name,
    game_type,
    tournament_type,
    entry_type,
    entry_fee,
    max_slots,
    start_date,
    end_date,
    description,
    prize_pool
  } = req.body;

  try {
    const connection = await pool.getConnection();

    const [result] = await connection.query(
      `INSERT INTO tournaments 
       (name, game_type, tournament_type, entry_type, entry_fee, max_slots, 
        start_date, end_date, description, prize_pool, created_by)
       VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?)`,
      [
        name,
        game_type || 'free_fire',
        tournament_type,
        entry_type,
        entry_fee || 0,
        max_slots,
        start_date,
        end_date,
        description,
        prize_pool || 0,
        req.userId
      ]
    );

    await connection.release();

    res.status(201).json({
      message: 'Tournament created successfully',
      tournament_id: result.insertId
    });
  } catch (error) {
    res.status(500).json({ error: error.message });
  }
});

// Join tournament
router.post('/:id/join', verifyToken, async (req, res) => {
  const { team_name, team_members } = req.body;
  const tournamentId = req.params.id;

  try {
    const connection = await pool.getConnection();

    // Get tournament details
    const [tournaments] = await connection.query(
      'SELECT * FROM tournaments WHERE id = ?',
      [tournamentId]
    );

    if (tournaments.length === 0) {
      await connection.release();
      return res.status(404).json({ error: 'Tournament not found' });
    }

    const tournament = tournaments[0];

    // Check slots
    if (tournament.booked_slots >= tournament.max_slots) {
      await connection.release();
      return res.status(400).json({ error: 'Tournament slots full' });
    }

    // Get user details
    const [users] = await connection.query(
      'SELECT wallet_balance FROM users WHERE id = ?',
      [req.userId]
    );

    const user = users[0];

    // Check wallet balance if paid entry
    if (tournament.entry_type === 'paid' && user.wallet_balance < tournament.entry_fee) {
      await connection.release();
      return res.status(400).json({ error: 'Insufficient wallet balance' });
    }

    // Register user
    const paymentStatus = tournament.entry_type === 'free' ? 'completed' : 'pending';

    await connection.query(
      `INSERT INTO tournament_registrations 
       (tournament_id, user_id, team_name, team_members, payment_status, amount_paid)
       VALUES (?, ?, ?, ?, ?, ?)`,
      [tournamentId, req.userId, team_name, JSON.stringify(team_members), paymentStatus, tournament.entry_fee]
    );

    // Update booked slots
    await connection.query(
      'UPDATE tournaments SET booked_slots = booked_slots + 1 WHERE id = ?',
      [tournamentId]
    );

    // Deduct entry fee from wallet if paid
    if (tournament.entry_type === 'paid') {
      await connection.query(
        'UPDATE users SET wallet_balance = wallet_balance - ? WHERE id = ?',
        [tournament.entry_fee, req.userId]
      );

      // Log transaction
      await connection.query(
        `INSERT INTO transactions 
         (user_id, transaction_type, amount, payment_method, status, description, reference_id)
         VALUES (?, ?, ?, ?, ?, ?, ?)`,
        [req.userId, 'entry_fee', tournament.entry_fee, 'wallet', 'success', `Entry fee for tournament ${tournamentId}`, tournamentId]
      );
    }

    await connection.release();

    res.json({
      message: 'Joined tournament successfully',
      payment_status: paymentStatus
    });
  } catch (error) {
    res.status(500).json({ error: error.message });
  }
});

module.exports = router;
```

