```javascript
const express = require('express');
const pool = require('../config/database');
const { verifyToken } = require('../middleware/auth');
const Razorpay = require('razorpay');
const router = express.Router();

const razorpay = new Razorpay({
  key_id: process.env.RAZORPAY_KEY_ID,
  key_secret: process.env.RAZORPAY_KEY_SECRET
});

// Get wallet balance
router.get('/balance', verifyToken, async (req, res) => {
  try {
    const connection = await pool.getConnection();
    const [users] = await connection.query(
      'SELECT wallet_balance FROM users WHERE id = ?',
      [req.userId]
    );
    await connection.release();

    if (users.length === 0) {
      return res.status(404).json({ error: 'User not found' });
    }

    res.json({ wallet_balance: users[0].wallet_balance });
  } catch (error) {
    res.status(500).json({ error: error.message });
  }
});

// Add money via Razorpay
router.post('/add-money', verifyToken, async (req, res) => {
  const { amount } = req.body;

  try {
    const order = await razorpay.orders.create({
      amount: amount * 100,
      currency: 'INR',
      receipt: `receipt_${req.userId}_${Date.now()}`
    });

    res.json({
      order_id: order.id,
      amount: order.amount / 100,
      currency: order.currency
    });
  } catch (error) {
    res.status(500).json({ error: error.message });
  }
});

// Verify payment and credit wallet
router.post('/verify-payment', verifyToken, async (req, res) => {
  const { payment_id, order_id, signature, amount } = req.body;

  try {
    const crypto = require('crypto');
    const body = order_id + '|' + payment_id;
    const expectedSignature = crypto
      .createHmac('sha256', process.env.RAZORPAY_KEY_SECRET)
      .update(body)
      .digest('hex');

    if (expectedSignature !== signature) {
      return res.status(400).json({ error: 'Payment verification failed' });
    }

    const connection = await pool.getConnection();

    // Update wallet
    await connection.query(
      'UPDATE users SET wallet_balance = wallet_balance + ? WHERE id = ?',
      [amount, req.userId]
    );

    // Log transaction
    await connection.query(
      `INSERT INTO transactions 
       (user_id, transaction_type, amount, payment_method, transaction_id, status)
       VALUES (?, ?, ?, ?, ?, ?)`,
      [req.userId, 'deposit', amount, 'razorpay', payment_id, 'success']
    );

    await connection.release();

    res.json({ message: 'Payment verified and wallet credited' });
  } catch (error) {
    res.status(500).json({ error: error.message });
  }
});

// Request withdrawal
router.post('/withdraw', verifyToken, async (req, res) => {
  const { amount, payment_method, bank_account, upi_id, paytm_number } = req.body;

  try {
    const connection = await pool.getConnection();

    // Check wallet balance
    const [users] = await connection.query(
      'SELECT wallet_balance FROM users WHERE id = ?',
      [req.userId]
    );

    if (users[0].wallet_balance < amount) {
      await connection.release();
      return res.status(400).json({ error: 'Insufficient balance' });
    }

    // Create withdrawal request
    await connection.query(
      `INSERT INTO withdrawals 
       (user_id, amount, payment_method, bank_account, upi_id, paytm_number)
       VALUES (?, ?, ?, ?, ?, ?)`,
      [req.userId, amount, payment_method, bank_account, upi_id, paytm_number]
    );

    // Deduct from wallet
    await connection.query(
      'UPDATE users SET wallet_balance = wallet_balance - ? WHERE id = ?',
      [amount, req.userId]
    );

    await connection.release();

    res.json({ message: 'Withdrawal request submitted' });
  } catch (error) {
    res.status(500).json({ error: error.message });
  }
});

// Get transactions
router.get('/transactions', verifyToken, async (req, res) => {
  try {
    const connection = await pool.getConnection();
    const [transactions] = await connection.query(
      'SELECT * FROM transactions WHERE user_id = ? ORDER BY created_at DESC LIMIT 50',
      [req.userId]
    );
    await connection.release();

    res.json(transactions);
  } catch (error) {
    res.status(500).json({ error: error.message });
  }
});

module.exports = router;
