const express = require('express');
const pool = require('../config/database');
const { verifyToken, verifyAdmin } = require('../middleware/auth');
const router = express.Router();

// Submit match results
router.post('/', verifyToken, async (req, res) => {
  const { match_id, kills, placement, points } = req.body;

  try {
    const connection = await pool.getConnection();

    // Check if already submitted
    const [existing] = await connection.query(
      'SELECT * FROM match_results WHERE match_id = ? AND user_id = ?',
      [match_id, req.userId]
    );

    if (existing.length > 0) {
      await connection.release();
      return res.status(400).json({ error: 'Result already submitted' });
    }

    // Insert result
    await connection.query(
      `INSERT INTO match_results 
       (match_id, user_id, kills, placement, points)
       VALUES (?, ?, ?, ?, ?)`,
      [match_id, req.userId, kills, placement, points]
    );

    await connection.release();

    res.json({ message: 'Result submitted successfully' });
  } catch (error) {
    res.status(500).json({ error: error.message });
  }
});

// Approve result (Admin)
router.post('/:id/approve', verifyAdmin, async (req, res) => {
  try {
    const connection = await pool.getConnection();

    const [results] = await connection.query(
      'SELECT * FROM match_results WHERE id = ?',
      [req.params.id]
    );

    if (results.length === 0) {
      await connection.release();
      return res.status(404).json({ error: 'Result not found' });
    }

    const result = results[0];

    // Update result status
    await connection.query(
      'UPDATE match_results SET verification_status = "approved", verified_by = ?, verified_at = NOW() WHERE id = ?',
      [req.userId, req.params.id]
    );

    // Update leaderboard
    const [matches] = await connection.query(
      'SELECT tournament_id FROM matches WHERE id = ?',
      [result.match_id]
    );

    if (matches.length > 0) {
      const tournamentId = matches[0].tournament_id;

      await connection.query(
        `INSERT INTO leaderboards (tournament_id, user_id, total_kills, total_points, best_placement)
         VALUES (?, ?, ?, ?, ?)
         ON DUPLICATE KEY UPDATE
         total_kills = total_kills + ?,
         total_points = total_points + ?,
         best_placement = IF(? < best_placement OR best_placement IS NULL, ?, best_placement)`,
        [tournamentId, result.user_id, result.kills, result.points, result.placement, 
         result.kills, result.points, result.placement, result.placement]
      );
    }

    await connection.release();

    res.json({ message: 'Result approved' });
  } catch (error) {
    res.status(500).json({ error: error.message });
  }
});

module.exports = router;
