export const getCurrentTime = (timezoneId = 'UTC') => {
  const now = new Date();

  try {
    // Use Intl API for accurate timezone conversion
    const formatter = new Intl.DateTimeFormat('en-US', {
      timeZone: timezoneId,
      hour: '2-digit',
      minute: '2-digit',
      second: '2-digit',
      hour12: false
    });

    const parts = formatter.formatToParts(now);
    const timeObject = {};

    parts.forEach(part => {
      if (part.type !== 'literal') {
        timeObject[part.type] = part.value;
      }
    });

    return {
      hour: parseInt(timeObject.hour),
      minute: parseInt(timeObject.minute),
      second: parseInt(timeObject.second),
      period: parseInt(timeObject.hour) >= 12 ? 'PM' : 'AM',
      hour12: ((parseInt(timeObject.hour) % 12) || 12).toString().padStart(2, '0')
    };
  } catch (error) {
    console.error('Error getting time for timezone:', timezoneId, error);
    return { hour: 0, minute: 0, second: 0, period: 'AM', hour12: '00' };
  }
};

export const formatTime = (hour, minute, second, format24 = true) => {
  const pad = (num) => String(num).padStart(2, '0');

  if (format24) {
    return `${pad(hour)}:${pad(minute)}:${pad(second)}`;
  }

  const hour12 = hour % 12 || 12;
  const period = hour >= 12 ? 'PM' : 'AM';
  return `${pad(hour12)}:${pad(minute)}:${pad(second)} ${period}`;
};

export const getClockHands = (hour, minute, second) => {
  // Convert to 12-hour format for analog clock
  const h = hour % 12;

  // Calculate degrees
  const secondDegrees = (second / 60) * 360;
  const minuteDegrees = (minute / 60) * 360 + (second / 60) * 6;
  const hourDegrees = (h / 12) * 360 + (minute / 60) * 30;

  return {
    second: secondDegrees,
    minute: minuteDegrees,
    hour: hourDegrees
  };
};

export const getTimeOfDay = (hour) => {
  if (hour >= 5 && hour < 12) return 'Morning';
  if (hour >= 12 && hour < 17) return 'Afternoon';
  if (hour >= 17 && hour < 21) return 'Evening';
  return 'Night';
};

export const getTimeDifference = (tz1, tz2) => {
  // Get the offset for both timezones
  const getOffset = (tz) => {
    try {
      const formatter = new Intl.DateTimeFormat('en-US', {
        timeZone: tz,
        hour: '2-digit',
        minute: '2-digit',
        second: '2-digit',
        hour12: false
      });

      const now = new Date();
      const formatter2 = new Intl.DateTimeFormat('en-US', {
        hour: '2-digit',
        minute: '2-digit',
        second: '2-digit',
        hour12: false
      });

      const tzTime = new Date(formatter.format(now));
      const utcTime = new Date(formatter2.format(now));

      return (utcTime - tzTime) / (1000 * 60 * 60);
    } catch {
      return 0;
    }
  };

  return Math.round((getOffset(tz2) - getOffset(tz1)) * 2) / 2;
};

export const getRandomColor = (timezoneId) => {
  const colors = [
    '#FF6B6B', '#4ECDC4', '#45B7D1', '#FFA07A',
    '#98D8C8', '#F7DC6F', '#BB8FCE', '#85C1E2',
    '#F8B739', '#52C41A', '#1890FF', '#EB2F96'
  ];

  let hash = 0;
  for (let i = 0; i < timezoneId.length; i++) {
    hash = timezoneId.charCodeAt(i) + ((hash << 5) - hash);
  }

  return colors[Math.abs(hash) % colors.length];
};
